var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"보안국은 건국기념전당 앞에서 발생한 폭발 사고가 반정부 단체인 <color=#ffd34c>순혈지식 연대</color>의 계획적인 사보타주라고 발표했습니다.","JPN":"保安局は、建国記念館の前で発生した爆発事故が反政府団体である<color=#ffd34c>純血知識連帯</color>の計画的なサボタージュだと発表しました。","ENG":"The Department of National Security has announced that the explosion in front of the National Foundation Hall was a terrorist attack planned by the anti-government organization <color=#ffd34c>Pureblood Knowledge Regiment</color>","TWN":"安全局表示，於建國紀念堂前發生的爆炸事件，是反政府團體 <color=#ffd34c>純血知識年代</color>有計畫性的攻擊行動。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"건국절 기념 공연의 관객들을 노린 이 사고로 인해 수백 명의 사망자가 발생하였으며…….","JPN":"建国記念公演の観客を狙ったこの事件により、数百人が死亡し……","ENG":"Hundreds of people in attendance at the National Foundation Day event were killed.….","TWN":"此次的攻擊，造成數百位來欣賞國慶表演的觀眾死亡……"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"지난번 사태에 휘말렸던 음악가, 루이제 슈나이더 씨의 의식이 회복되었다는 소식입니다.","JPN":"以前の事態に巻き込まれた音楽家、ルイーゼ・シュナイダー氏が意識を取り戻しました。","ENG":"It is reported that Louise Schneider, a famous musician who attended the performance, has regained consciousness.","TWN":"捲入上次事件的音樂家 露易絲·修奈德，據說已經恢復意識。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"주치의는 슈나이더 씨가 중추신경 손상으로 하반신이 마비되었다고 전해, 반정부 단체에 대한 국민의 공분을 불러일으킨 바 있습니다.","JPN":"主治医はシュナイダー氏が中枢神経の損傷で下半身が麻痺した事実を伝え、反政府団体への国民の怒りを呼び起こしました。","ENG":"The doctors say she has been paralyzed from the waist down, sparking public outrage towards the anti-government forces.","TWN":"主治醫生表示，修奈德的中樞神經受損，導致下半身麻痺。而反政府團體的作為，已經引發全國人民的憤怒。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"뉴스 중의 뉴스, 진짜 뉴스를 전하는 <color=#ffd34c>국민의 노래</color>.","JPN":"ニュースの中のニュース、本当のニュースをお伝えする<color=#ffd34c>民の歌</color>。","ENG":"The news of the news! <color=#ffd34c>The Voice of the People</color>, reporting the real truth.","TWN":"重磅新聞，只報導真正新聞的<color=#ffd34c>人民之聲</color>。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘 영상에서는 현장에서 살아남은 슈나이더 모녀에 대해 다루고자 합니다.","JPN":"今日の動画では、現場で生き残ったシュナイダー親子について話します。","ENG":"In today's video, we're going to break down the news on two survivors, Louis Schneider and her daughter.","TWN":"今天想要討論的內容，是有關於在爆炸事件中倖存下來的修奈德母女。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"이번 내용, 끝까지 봐도 후회 안 하실 겁니다. 다 보시고 난 뒤 구독과 좋아요 잊지 마세요.","JPN":"今回の内容、最後まで見ても後悔はしないはずです。視聴後、チャンネル登録とイイね！をお忘れなく。","ENG":"You’ll regret it if you don’t watch till the end! And don’t forget to like and subscribe for amazing content!","TWN":"一定要看到最後，保證你不會後悔！看完後別忘記按讚加訂閱喔！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"루이제 슈나이더, 사진으로 보시다시피 처음 데뷔할 때부터 그 미모로 호평을 받았는데요.","JPN":"ルイーゼ・シュナイダー、写真でおわかりのように、デビューした時からその美しさで話題となりました。","ENG":"Louise Schneider, as you can see from this picture, has been well known for her beauty ever since she debuted.","TWN":"露易絲·修奈德，從照片上可以看到，從她出道開始，就因她的美貌而受到大家喜愛。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"저희 넷튜브 채널을 통해 접촉해 온 제보자에 따르면, 반군들에게 딸과 자신의 안전을 대가로 몸을……","JPN":"我らのネットチューブチャンネルを通じて接触してきた情報提供者によりますと、娘と自分の身の安全の見返りに反乱軍に身を……","ENG":"And according to an informant connected with our NetTube channel, in exchange for her and her daughter’s safety, she was forced to sell her body...","TWN":"但是我們收到內幕消息，據說她以自己和女兒的安全為代價，獻身給叛軍……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……그래서 확보한 건 결국 그 악보뿐이라는 건가?","JPN":"……それで、確保したのは結局その楽譜だけなのか？","ENG":"...Anyways, is the musical score the only thing you secured?","TWN":"……所以你們只有找到那個樂譜嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네, 침식체는 사살 직후 신체가 붕괴하더군요.","JPN":"はい。侵食体は射殺直後に体が崩壊しました。","ENG":"That’s correct. The Corrupted Object collapsed immediately after being shot.","TWN":"對，射殺侵蝕體後，它的身體就開始解體。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"인간의 생체 조직 일부가 남은 걸로 봐선, 변이가 급격하게 진행된 모양이에요.","JPN":"人間の生体組織が一部残ってるところを見ると、急激に変異したようです。","ENG":"Given that some of the human biological tissue remains, the mutation seems to have occurred only recently.","TWN":"從它還留有部分人體組織來看，應該是在很緊急的情況下變異的。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"침식 증후군으로 인한 말로라기에는 석연치 않군.","JPN":"侵食症候群による末路にしては釈然としないな。","ENG":"But we can’t be sure due to the Corruption Syndrome.","TWN":"但這也無法解釋是因為侵蝕症候群而造成的。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그 침식지대의 CSE 레벨은 2를 넘지 않아. 그런데도 그 며칠 사이 2종 침식체가 되었다면……","JPN":"あの侵食地帯のCSEレベルは2に満たない。なのに、この何日間で第2種侵食体になったのなら……","ENG":"That Corrupted Area’s CSE level has never exceeded level 2. And yet, just a few days ago, a Category 2 Corrupted Object...","TWN":"那個侵蝕地帶的CSE等級不到2，要在這短的時間內變成2類侵蝕體……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};